// GunionHandshake.cpp
#include "stdafx.h"
#include "GunionHandshake.h"
#include "LoginClient.h"
#include "Tracer.h"

///////////////////////////////////////////////////////////////////////////////
// GunionHandshake
//------------------------------------------------------------------------------
// 说明：
//   - Gunion-WeGame 安全握手流程控制器
//   - 仅负责“流程 + 状态”，不直接处理网络、不直接处理线程
///////////////////////////////////////////////////////////////////////////////

GunionHandshake::GunionHandshake(LoginClient* owner)
	: m_owner(owner)
	, m_finished(false)
	, m_success(false)
	, m_started(false)
{
}

///////////////////////////////////////////////////////////////////////////////
// 启动握手流程（异步状态机入口）
//
// 说明：
//   - 本函数不会同步完成整个握手流程
//   - 每次调用只推进“当前状态下的下一步”
//   - 后续步骤由对应的语义回调继续推进
///////////////////////////////////////////////////////////////////////////////
bool GunionHandshake::Start()
{
	TRACET();

	// 安全校验
	if (!m_owner)
		return false;

	// 若流程已经结束（成功或失败），不再重复推进
	if (m_finished)
		return false;

	// 已经启动过，不要重复发请求
	if (m_started)
		return true;

	// 标记：握手流程已启动
	m_started = true;

	// 启动握手流程：获取公钥
	return m_owner->StartGunionGetPublicKey();
}

///////////////////////////////////////////////////////////////////////////////
// 是否需要重新获取 PublicKey
///////////////////////////////////////////////////////////////////////////////
bool GunionHandshake::NeedGetPublicKey() const
{
	return m_publicKey.empty();
}

///////////////////////////////////////////////////////////////////////////////
// GetPublicKey 成功回调
//
// @param publicKey 服务端下发的公钥
///////////////////////////////////////////////////////////////////////////////
void GunionHandshake::OnPublicKeyReady(const std::string& publicKey)
{
	TRACET();

	// 若流程已经结束，不再处理
	if (m_finished)
		return;

	// 保存公钥
	m_publicKey = publicKey;

	// 推进流程：已有公钥 → 发起 Handshake（协商会话密钥）
	if (m_owner)
	{
		m_owner->StartGunionHandshake(m_publicKey);
	}
}

///////////////////////////////////////////////////////////////////////////////
// GetPublicKey 失败回调
//
// @param reason 失败原因（语义级）
///////////////////////////////////////////////////////////////////////////////
void GunionHandshake::OnPublicKeyFailed(int /*reason*/)
{
	TRACET();

	// 结束流程，标记失败
	m_finished = true;
	m_success = false;
}

///////////////////////////////////////////////////////////////////////////////
// HandShake 成功回调
///////////////////////////////////////////////////////////////////////////////
void GunionHandshake::OnHandShakeSuccess()
{
	TRACET();

	// 结束流程，标记成功
	m_finished = true;
	m_success = true;
}

///////////////////////////////////////////////////////////////////////////////
// NegotiateKey 失败回调
//
// @param reason 失败原因（语义级）
///////////////////////////////////////////////////////////////////////////////
void GunionHandshake::OnHandShakeFailed(int /*reason*/)
{
	TRACET();

	// 结束流程，标记失败
	m_finished = true;
	m_success = false;
}

///////////////////////////////////////////////////////////////////////////////
// 握手是否已结束
///////////////////////////////////////////////////////////////////////////////
bool GunionHandshake::IsFinished() const
{
	return m_finished;
}

///////////////////////////////////////////////////////////////////////////////
// 握手是否成功
///////////////////////////////////////////////////////////////////////////////
bool GunionHandshake::IsSuccess() const
{
	return m_finished && m_success;
}

///////////////////////////////////////////////////////////////////////////////
// 握手流程重置
///////////////////////////////////////////////////////////////////////////////
void GunionHandshake::Reset()
{
	TRACET();

	m_started = false;
	m_finished = false;
	m_success = false;
	m_publicKey.clear();
}